Javascript.validate:
var description = Services.getValue(REF_DATA_XPATH + "/ReasonForReferralList/ReasonForReferral[./Value = " + ReasonForReferral.dataBinding + "]/Description");
var valueTest = Services.getValue( REF_DATA_XPATH + "/ReasonForReferralList/ReasonForReferral[./Description = " + ReasonForReferral.dataBinding + "]/Value" );
if (description == null && valueTest == null)
{
	// This is not a valid value - see list of Values
	return ErrorCode.getErrorCode("CaseMan_Reports_Invalid_LOV_Msg");
}
else
{
	return null;
}

Javascript.transformToDisplay:
var description = Services.getValue( REF_DATA_XPATH + "/ReasonForReferralList/ReasonForReferral[./Value = " + ReasonForReferral.dataBinding + "]/Description" );
if (description != null)
{
	return description;
}
else
{
	return value;
}

Javascript.miscCode:
ReasonForReferral.componentName =	"Reason for Referral";
ReasonForReferral.srcData = 		REF_DATA_XPATH + "/ReasonForReferralList";
ReasonForReferral.rowXPath = 		"ReasonForReferral";
ReasonForReferral.keyXPath =		"Value";

function ReasonForReferralLOVButton() {};
ReasonForReferralLOVButton.tabIndex = __tabIdx++;

function ReasonForReferralLOVGrid() {};

ReasonForReferralLOVGrid.dataBinding = ReasonForReferral.dataBinding;
ReasonForReferralLOVGrid.srcData = REF_DATA_XPATH + "/ReasonForReferralList";
ReasonForReferralLOVGrid.rowXPath = "ReasonForReferral";
ReasonForReferralLOVGrid.keyXPath = "Value";
ReasonForReferralLOVGrid.columns = [
	{xpath: "Value"},
	{xpath: "Description"}
];

ReasonForReferralLOVGrid.raise = {
	eventBinding: {
		singleClicks: [ {element: "ReasonForReferralLOVButton"} ],
		keys: [ { key: Key.F6, element: "ReasonForReferral" } ]
	}
};

ReasonForReferralLOVGrid.nextFocusedAdaptorId = function() {
	return "OtherReferralReason";
}
